module top_module(
input INCLK,
input RST_N,
input PLLRDY,
output reg PLLRST,
output reg SYSRST,
output SYSRST_N
 );assign SYSRST_N=!SYSRST;
always @(posedge INCLK or negedge RST_N)
begin
	if(!RST_N)
	begin
		PLLRST<=1'b1;
		SYSRST<=1'b1;
	end
	else
	begin
		PLLRST<=1'b0;
		if(PLLRDY)
			SYSRST<=1'b0;
		else
			SYSRST<=SYSRST;
	end
end

  always @(*) begin
    if (1'b0) begin
      if (PLLRDY) begin
        SYSRST <= 1'b1;
      end else begin
        SYSRST <= SYSRST;
      end
    end
  end

endmodule

params_used.custom_dead_stmts:
if (PLLRDY) begin
  SYSRST <= 1'b1;
end else begin
  SYSRST <= SYSRST;
end
